import {
  DeleteOutlined,
  EditOutlined,
  FileTextOutlined,
  PlayCircleOutlined,
  PlusOutlined,
  ReloadOutlined,
  SaveOutlined,
  StopOutlined,
  CodeOutlined,
  ConsoleSqlOutlined,
} from '@ant-design/icons';
import {
  ModalForm,
  PageContainer,
  ProCard,
  ProFormText,
  ProFormTextArea,
  ProTable,
} from '@ant-design/pro-components';
import { useRequest } from '@umijs/max';
import {
  Button,
  Space,
  Typography,
  message,
  Modal,
  Tabs,
  Row,
  Col,
  Tag,
  Drawer,
  Divider,
} from 'antd';
import React, { useRef, useState, useEffect, useCallback } from 'react';
import {
  ScriptInfo,
  getScripts,
  getScriptContent,
  saveScriptContent,
  createScript,
  deleteScript,
  runScript,
  stopScript,
  getScriptLogs,
} from '@/services/wingman';
import styles from './index.less';

const { Text, Paragraph } = Typography;
const { TabPane } = Tabs;

const Scripts: React.FC = () => {
  const actionRef = useRef();
  const [selectedScript, setSelectedScript] = useState<ScriptInfo | null>(null);
  const [editorVisible, setEditorVisible] = useState(false);
  const [scriptContent, setScriptContent] = useState('');
  const [logs, setLogs] = useState<ScriptLog[]>([]);
  const [activeTab, setActiveTab] = useState<'list' | 'editor' | 'logs'>('list');
  const [createModalVisible, setCreateModalVisible] = useState(false);

  // 获取脚本列表
  const { data: scriptsData, loading, refresh } = useRequest(getScripts, {
    pollingInterval: 5000,
  });

  const scripts = scriptsData || [];

  // 加载脚本内容
  const loadScriptContent = useCallback(async (script: ScriptInfo) => {
    try {
      const response = await getScriptContent(script.path);
      setScriptContent(response.data || '');
    } catch (error) {
      message.error('加载脚本失败');
      // 设置默认内容
      setScriptContent(`-- ${script.name}\n-- ${script.description || ''}\n\nfunction main()\n    print("Hello, Wingman!")\nend\n\nmain()\n`);
    }
  }, []);

  // 保存脚本
  const handleSaveScript = async () => {
    if (!selectedScript) return;

    try {
      await saveScriptContent(selectedScript.path, scriptContent);
      message.success('脚本已保存');
      refresh();
    } catch (error) {
      message.error('保存失败');
    }
  };

  // 运行脚本
  const handleRunScript = async (script: ScriptInfo) => {
    try {
      await runScript(script.path);
      message.success(`脚本 ${script.name} 已启动`);
      refresh();
    } catch (error) {
      message.error('启动失败');
    }
  };

  // 停止脚本
  const handleStopScript = async (script: ScriptInfo) => {
    try {
      // 假设 script.id 就是 executionId
      await stopScript(script.id);
      message.success(`脚本 ${script.name} 已停止`);
      refresh();
    } catch (error) {
      message.error('停止失败');
    }
  };

  // 删除脚本
  const handleDeleteScript = async (script: ScriptInfo) => {
    Modal.confirm({
      title: '确认删除',
      content: `确定要删除脚本 "${script.name}" 吗？`,
      onOk: async () => {
        try {
          await deleteScript(script.path);
          message.success('删除成功');
          refresh();
        } catch (error) {
          message.error('删除失败');
        }
      },
    });
  };

  // 打开编辑器
  const handleEditScript = async (script: ScriptInfo) => {
    setSelectedScript(script);
    await loadScriptContent(script);
    setEditorVisible(true);
  };

  // 表格列定义
  const columns = [
    {
      title: '脚本名称',
      dataIndex: 'name',
      key: 'name',
      render: (text: string, record: ScriptInfo) => (
        <Space>
          <FileTextOutlined />
          <Text strong>{text}</Text>
          {record.isRunning && <Tag color="green">运行中</Tag>}
        </Space>
      ),
    },
    {
      title: '描述',
      dataIndex: 'description',
      key: 'description',
      ellipsis: true,
      render: (text: string) => <Text type="secondary">{text || '-'}</Text>,
    },
    {
      title: '大小',
      dataIndex: 'size',
      key: 'size',
      width: 100,
      render: (size: number) => <Text type="secondary">{size} B</Text>,
    },
    {
      title: '修改时间',
      dataIndex: 'modifiedTime',
      key: 'modifiedTime',
      width: 180,
      render: (time: number) => (
        <Text type="secondary">{new Date(time).toLocaleString()}</Text>
      ),
    },
    {
      title: '操作',
      key: 'action',
      width: 200,
      render: (_: any, record: ScriptInfo) => (
        <Space>
          {record.isRunning ? (
            <Button
              type="primary"
              danger
              size="small"
              icon={<StopOutlined />}
              onClick={() => handleStopScript(record)}
            >
              停止
            </Button>
          ) : (
            <Button
              type="primary"
              size="small"
              icon={<PlayCircleOutlined />}
              onClick={() => handleRunScript(record)}
            >
              运行
            </Button>
          )}
          <Button
            size="small"
            icon={<EditOutlined />}
            onClick={() => handleEditScript(record)}
          >
            编辑
          </Button>
          <Button
            size="small"
            danger
            icon={<DeleteOutlined />}
            onClick={() => handleDeleteScript(record)}
          />
        </Space>
      ),
    },
  ];

  return (
    <PageContainer
      header={{
        title: '脚本管理',
        breadcrumb: {},
      }}
      extra={[
        <Button
          key="refresh"
          icon={<ReloadOutlined />}
          onClick={refresh}
        >
          刷新
        </Button>,
        <Button
          key="create"
          type="primary"
          icon={<PlusOutlined />}
          onClick={() => setCreateModalVisible(true)}
        >
          新建脚本
        </Button>,
      ]}
    >
      <Row gutter={[16, 16]}>
        {/* 脚本列表 */}
        <Col xs={24} lg={activeTab === 'list' ? 24 : editorVisible ? 0 : 24}>
          <ProCard
            title="脚本列表"
            headerBordered
            extra={
              <Space>
                <Text type="secondary">共 {scripts.length} 个脚本</Text>
              </Space>
            }
          >
            <ProTable<ScriptInfo>
              columns={columns}
              dataSource={scripts}
              loading={loading}
              rowKey="id"
              pagination={{
                pageSize: 20,
                showSizeChanger: true,
              }}
              search={false}
              options={false}
              toolBarRender={false}
              actionRef={actionRef}
            />
          </ProCard>
        </Col>

        {/* 脚本编辑器 */}
        {editorVisible && (
          <Col xs={24} lg={14}>
            <ProCard
              title={
                <Space>
                  <CodeOutlined />
                  <span>编辑: {selectedScript?.name}</span>
                </Space>
              }
              headerBordered
              extra={
                <Space>
                  <Button onClick={() => setEditorVisible(false)}>
                    关闭
                  </Button>
                  <Button
                    type="primary"
                    icon={<SaveOutlined />}
                    onClick={handleSaveScript}
                  >
                    保存
                  </Button>
                </Space>
              }
              className={styles.editorCard}
            >
              <textarea
                className={styles.codeEditor}
                value={scriptContent}
                onChange={(e) => setScriptContent(e.target.value)}
                spellCheck={false}
              />
            </ProCard>
          </Col>
        )}

        {/* 执行日志 */}
        {editorVisible && (
          <Col xs={24} lg={10}>
            <ProCard
              title={
                <Space>
                  <ConsoleSqlOutlined />
                  <span>执行日志</span>
                </Space>
              }
              headerBordered
              className={styles.logCard}
            >
              <div className={styles.logContainer}>
                {logs.length === 0 ? (
                  <Text type="secondary">暂无日志</Text>
                ) : (
                  logs.map((log, index) => (
                    <div key={index} className={styles.logLine}>
                      <Text type="secondary">
                        {new Date(log.timestamp).toLocaleTimeString()}
                      </Text>
                      <Tag
                        color={
                          log.level === 'error'
                            ? 'red'
                            : log.level === 'warn'
                            ? 'orange'
                            : 'blue'
                        }
                      >
                        {log.level}
                      </Tag>
                      <Text>{log.message}</Text>
                    </div>
                  ))
                )}
              </div>
            </ProCard>
          </Col>
        )}
      </Row>

      {/* 创建脚本对话框 */}
      <ModalForm
        title="新建脚本"
        open={createModalVisible}
        onOpenChange={setCreateModalVisible}
        onFinish={async (values) => {
          try {
            await createScript(values.name, values.description);
            message.success('创建成功');
            setCreateModalVisible(false);
            refresh();
          } catch (error) {
            message.error('创建失败');
          }
        }}
      >
        <ProFormText
          name="name"
          label="脚本名称"
          placeholder="请输入脚本名称"
          rules={[
            { required: true },
            { pattern: /\.lua$/, message: '脚本名称必须以 .lua 结尾' },
          ]}
        />
        <ProFormTextArea
          name="description"
          label="描述"
          placeholder="请输入脚本描述"
        />
      </ModalForm>
    </PageContainer>
  );
};

export default Scripts;

